import { db } from '../config/firebase';
import { collection, getDocs, query, where } from "firebase/firestore";
import Fuse from 'fuse.js';

export async function citysuggester(city_name) {
  const citiesRef = collection(db, 'City');
  const q = query(citiesRef, where('cityName', '>=', city_name), where('cityName', '<=', city_name + '\uf8ff'));
  const querySnapshot = await getDocs(q);

  const cityData = [];
  querySnapshot.forEach((doc) => {
    cityData.push(doc.data());
  });

  const options = {
    includeScore: true,
    keys: ['cityName']
  };
  const fuse = new Fuse(cityData, options);
  const result = fuse.search(city_name);
  console.log(result)

  if (result.length === 0) {
    return null;
  }

  return result[0].item.cityName;
}
